"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgePrimaryButton — drop-in `.btn-util.primary` that opens the
   Bridge overlay. Use in DeptHeader actions slot. Server components can
   include it without becoming client components themselves.

   Example:
     <DeptHeader actions={<BridgePrimaryButton dept="ops">Reorder critical → Bridge</BridgePrimaryButton>} />
   ════════════════════════════════════════════════════════════════════════ */

import { useBridge, type BridgeDept, type BridgePage } from "@/features/bridge/hooks/use-bridge";

export interface BridgePrimaryButtonProps {
  /** Which Bridge dept tab to open into. Defaults to "ops". */
  dept?: BridgeDept;
  /** Which Bridge page (execution flow) to land on. Defaults to "home". */
  page?: BridgePage;
  children: React.ReactNode;
  className?: string;
}

export function BridgePrimaryButton({
  dept = "ops",
  page,
  children,
  className = "btn-util primary",
}: BridgePrimaryButtonProps) {
  const { openBridge } = useBridge();
  return (
    <button className={className} onClick={() => openBridge(dept, page)} type="button">
      {children}
    </button>
  );
}
