/**
 * Mock data + economics for the Finance · Cash Forecast sub-page.
 *
 * The page projects 3 / 6 / 12 months forward and models three scenarios:
 *   - Base       — current trajectory
 *   - Conservative — revenue −20%
 *   - Growth     — spend +50%, revenue +25%
 *
 * The acquisition-spend slider re-drives the daily path for each scenario.
 */

export const HORIZON_DAYS = 360; // 12 months of model
export const SAFETY_FLOOR = 80_000;

export const START_CASH = 214_000;
export const BASE_REV_MO = 361_000;
export const CM3_RATE = 0.42; // contribution margin before ad spend + fixed burn
export const FIXED_BURN_MO = 92_000;
export const CURRENT_SPEND = 39_000;
export const SPEND_MIN = 20_000;
export const SPEND_MAX = 80_000;

/** Real one-off cash events that hit ALL scenarios. */
export const SEASONAL_EVENTS = [
  { day: 96, outflow: 66_000, label: "Q3 tax + peak buy" },
  { day: 250, outflow: 42_000, label: "Q4 inventory" },
] as const;

export type ScenarioKey = "base" | "cons" | "grow";

/**
 * Walk the daily cash path for a scenario.
 *   adSpendMo: monthly acquisition spend (slider-driven for base/cons; +50% for grow)
 *   revMult:   revenue multiplier (1.0 / 0.80 / 1.25)
 */
export function walkScenario(adSpendMo: number, revMult: number): number[] {
  const dailyNet =
    (BASE_REV_MO * revMult * CM3_RATE - adSpendMo - FIXED_BURN_MO) / 30;
  const out: number[] = new Array(HORIZON_DAYS + 1);
  for (let d = 0; d <= HORIZON_DAYS; d++) {
    let c = START_CASH + dailyNet * d;
    SEASONAL_EVENTS.forEach((ev) => {
      if (d >= ev.day) c -= ev.outflow;
    });
    out[d] = c;
  }
  return out;
}

