"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { RunwayChart } from "@/components/charts/RunwayChart";
import {
  HORIZON_DAYS,
  SAFETY_FLOOR,
  START_CASH,
  BASE_REV_MO,
  CM3_RATE,
  FIXED_BURN_MO,
  CURRENT_SPEND,
  SPEND_MIN,
  SPEND_MAX,
  SEASONAL_EVENTS,
  walkScenario,
  forecastAI,
} from "@/features/finance/api/finance-forecast-data";
import "./forecast.css";

const fmtK = (v: number) => {
  const a = Math.abs(v);
  const sign = v < 0 ? "−" : "";
  if (a >= 1_000_000) return `${sign}$${(a / 1_000_000).toFixed(2)}M`;
  return `${sign}$${Math.round(a / 1000)}K`;
};
const fmtKplain = (v: number) => {
  const a = Math.abs(v);
  if (a >= 1_000_000) return `$${(a / 1_000_000).toFixed(2)}M`;
  return `$${Math.round(a / 1000)}K`;
};
const fmtSpend = (v: number) => `$${(v / 1000).toFixed(0)}K`;
const fmtSpendFull = (v: number) => `$${v.toLocaleString()}`;

const HORIZONS = [90, 180, 360];
const HORIZON_LABELS = ["3 months", "6 months", "12 months"];

export default function ForecastPage() {
  const [horizonIdx, setHorizonIdx] = useState(1);
  const horizonView = HORIZONS[horizonIdx];
  const [spend, setSpend] = useState(CURRENT_SPEND);

  // Scenario paths reactive to spend
  const base = useMemo(() => walkScenario(spend, 1.0), [spend]);
  const cons = useMemo(() => walkScenario(spend, 0.8), [spend]);
  const grow = useMemo(() => walkScenario(spend * 1.5, 1.25), [spend]);

  // Within visible horizon, find lowest point of each
  const lowOf = (pts: number[]) => {
    let lowIdx = 0;
    for (let i = 1; i <= horizonView; i++) if (pts[i] < pts[lowIdx]) lowIdx = i;
    return { day: lowIdx, value: pts[lowIdx] };
  };
  const baseLow = useMemo(() => lowOf(base), [base, horizonView]);
  const baseEnd = base[horizonView];
  const consEnd = cons[horizonView];
  const growEnd = grow[horizonView];

  // Runway months (very simple proxy — kept for the argument copy)
  const monthlyBurn = FIXED_BURN_MO + spend - BASE_REV_MO * CM3_RATE;
  const runwayMonths = monthlyBurn > 0 ? baseEnd / monthlyBurn : 12 + 4;

  // Argument text
  const argument =
    spend < CURRENT_SPEND * 1.1
      ? `At current spend the base case lands near <b>${fmtKplain(baseEnd)}</b> with a comfortable floor. The model says you have real headroom — but watch the conservative line, which is where a soft month would actually take you.`
      : spend < CURRENT_SPEND * 1.35
        ? `At <b>${fmtSpend(spend)}/mo</b> you stretch the floor but the base case still clears safely at <b>${fmtKplain(baseEnd)}</b>. Margin for surprise is shrinking.`
        : `At <b>${fmtSpend(spend)}/mo</b> the conservative case drops to <b>${fmtKplain(consEnd)}</b> — closing in on the $80K floor. Past here you're betting on the upside.`;

  return (
    <div className="finance-forecast-page">
      <DeptHeader
        dept="finance"
        title="Cash Forecast"
        meta={
          <>
            <span className="live">Live</span> · Where the runway goes from here · modeled from your ledger
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Plan in Bridge →</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={HORIZON_LABELS} activeIndex={horizonIdx} onChange={setHorizonIdx} />

      {/* Modeled note */}
      <div className="modeled-note">
        <span className="mc" />
        <span className="mt">
          <b>This page is a projection, not a record.</b> Every figure below is modeled forward from your actual ledger — it shows where today&rsquo;s trajectory leads, not money that has moved. Drag the spend control to test a different future.
        </span>
      </div>

      <AIStrip label={forecastAI.label} meta={forecastAI.meta} cards={forecastAI.cards} />

      {/* Runway hero chart */}
      <SectionLabel>Runway under three futures</SectionLabel>
      <div className="runway-card">
        <div className="runway-head">
          <div className="runway-readout">
            <div className="rl">Projected cash · base case · end of horizon</div>
            <div className="rv">{fmtKplain(baseEnd)}</div>
            <div className="rsub">
              lowest point <b>{fmtKplain(baseLow.value)}</b> on day {baseLow.day}
            </div>
          </div>
          <div className="runway-legend">
            <div className="rleg" style={{ color: "var(--d-finance)" }}>
              <span className="sw" />Base case
            </div>
            <div className="rleg" style={{ color: "var(--loss)" }}>
              <span className="sw dash" />Conservative · revenue −20%
            </div>
            <div className="rleg" style={{ color: "var(--d-growth)" }}>
              <span className="sw dash" />Growth mode · scaled spend
            </div>
          </div>
        </div>
        <RunwayChart
          scenarios={{ base, conservative: cons, growth: grow }}
          horizonView={horizonView}
          safetyFloor={SAFETY_FLOOR}
          events={SEASONAL_EVENTS}
        />
      </div>

      {/* Slider */}
      <div className="slider-card">
        <div className="slider-top">
          <div className="slider-label">
            Monthly acquisition spend
            <span className="info">i</span>
          </div>
          <div className="slider-val">
            {fmtSpendFull(spend)}<span className="vs">/mo</span>
          </div>
        </div>
        <input
          type="range"
          min={SPEND_MIN}
          max={SPEND_MAX}
          step={1000}
          value={spend}
          onChange={(e) => setSpend(parseInt(e.target.value, 10))}
        />
        <div className="slider-scale">
          <span>{fmtSpend(SPEND_MIN)}</span>
          <span className="now-tick">{fmtSpend(CURRENT_SPEND)} · current</span>
          <span>{fmtSpend(SPEND_MAX)}</span>
        </div>
      </div>

      <div className="argument">
        <span className="mk" />
        <p dangerouslySetInnerHTML={{ __html: argument }} />
      </div>

      {/* Month-end projection */}
      <SectionLabel>Month-end projection</SectionLabel>
      <div className="proj-card">
        <div className="proj-strip">
          <div className="proj">
            <div className="proj-label">
              Projected revenue <span className="tag">Modeled</span>
            </div>
            <div className="proj-val">{fmtKplain(BASE_REV_MO)}</div>
            <div className="proj-sub vs">
              vs target <b>$340K</b> · +6%
            </div>
          </div>
          <div className="proj">
            <div className="proj-label">
              Projected profit · CM3 <span className="tag">Modeled</span>
            </div>
            <div className="proj-val fin">
              {fmtKplain(BASE_REV_MO * CM3_RATE - FIXED_BURN_MO - spend)}
            </div>
            <div className="proj-sub">
              {((((BASE_REV_MO * CM3_RATE) - FIXED_BURN_MO - spend) / BASE_REV_MO) * 100).toFixed(1)}% contribution margin
            </div>
          </div>
          <div className="proj">
            <div className="proj-label">
              Projected runway <span className="tag">Modeled</span>
            </div>
            <div className="proj-val">
              {Math.max(0, runwayMonths).toFixed(1)} mo
            </div>
            <div className="proj-sub">at end-of-month burn</div>
          </div>
        </div>
        <div className="confidence-row">
          <span className="cdot" />
          <span>
            <b>Confidence</b> · projected from 22 days of actual May data. The more the month completes, the tighter this gets.
          </span>
        </div>
      </div>

      {/* Scenario table */}
      <SectionLabel>Cash position by scenario</SectionLabel>
      <div className="scen-table">
        <div className="scen-head">
          <span className="c">Scenario</span>
          <span className="c r">In 3 months</span>
          <span className="c r">In 6 months</span>
          <span className="c r">In 12 months</span>
          <span className="c r">Runway</span>
        </div>
        {[
          { key: "base", name: "Base case", sub: "current trajectory", pts: base, color: "" },
          { key: "cons", name: "Conservative", sub: "revenue −20%", pts: cons, color: "" },
          { key: "grow", name: "Growth mode", sub: "spend +50%, revenue +25%", pts: grow, color: "" },
        ].map((s) => {
          const v3 = s.pts[90];
          const v6 = s.pts[180];
          const v12 = s.pts[360];
          const cls = (v: number) => (v < SAFETY_FLOOR ? "alert" : v > START_CASH * 2 ? "ok" : "");
          return (
            <div key={s.key} className="scen-row">
              <span className="sn">
                <span className={`swatch ${s.key}`} />
                <span>
                  {s.name}
                  <span className="sub">{s.sub}</span>
                </span>
              </span>
              <span className={`v ${cls(v3)}`}>{fmtKplain(v3)}</span>
              <span className={`v ${cls(v6)}`}>{fmtKplain(v6)}</span>
              <span className={`v ${cls(v12)}`}>{fmtKplain(v12)}</span>
              <span className="v">
                {s.key === "cons" && cons[HORIZON_DAYS] < SAFETY_FLOOR
                  ? "tight"
                  : s.key === "grow"
                    ? "—"
                    : `${Math.max(0, runwayMonths).toFixed(1)} mo`}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
