"use client";

/**
 * <RunwayChart> — 3-scenario cash-runway projection (base / conservative / growth)
 * with safety-floor, today beacon, seasonal markers, and end nodes.
 *
 * Tier-2 per CHART-STANDARD §5.1. viewBox = real px width via useChartSize.
 */

import { useChartSize } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface SeasonalEvent {
  day: number;
  label: string;
}

export interface RunwayScenarios {
  base: number[];
  conservative: number[];
  growth: number[];
}

export interface RunwayChartProps {
  /** Three scenario series indexed by day [0..horizonMax]. */
  scenarios?: RunwayScenarios;
  /** Days into the future to render (must be <= scenarios.base.length - 1). */
  horizonView?: number;
  /** Hard floor in dollars — line + filled danger zone. */
  safetyFloor?: number;
  /** Optional seasonal markers (Black Friday, etc.). */
  events?: readonly SeasonalEvent[];
  state?: ChartState;
  /** Label used in empty/error copy. */
  label?: string;
}

const fmtK = (v: number) => {
  const a = Math.abs(v);
  if (a >= 1_000_000) return `$${(a / 1_000_000).toFixed(2)}M`;
  return `$${Math.round(a / 1000)}K`;
};

/** Trivial sample so the component is renderable with zero props (§4). */
function sampleSeries(spend: number): number[] {
  const start = 600_000;
  const pts: number[] = [];
  for (let d = 0; d <= 360; d++) {
    pts.push(start + (d / 360) * (start * 0.4) - (spend / 30) * d * 0.05);
  }
  return pts;
}
export const sampleRunwayScenarios: RunwayScenarios = {
  base: sampleSeries(30000),
  conservative: sampleSeries(30000).map((v) => v * 0.85),
  growth: sampleSeries(45000).map((v) => v * 1.05),
};
export const sampleRunwaySeasonalEvents: SeasonalEvent[] = [
  { day: 60, label: "BFCM" },
  { day: 180, label: "Q2 reset" },
];

export function RunwayChart({
  scenarios = sampleRunwayScenarios,
  horizonView = 180,
  safetyFloor = 80_000,
  events = sampleRunwaySeasonalEvents,
  state = "ready",
  label = "Runway",
}: RunwayChartProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 920 });
  const W = Math.max(640, width);
  const H = 320;
  const padL = 8;
  const padT = 24;
  const padB = 46;
  const padR = W - 20;
  const plotW = padR - padL;
  const plotH = H - padT - padB;

  const { base, conservative: cons, growth: grow } = scenarios;

  let hi = safetyFloor;
  for (let i = 0; i <= horizonView; i++) {
    hi = Math.max(hi, base[i] ?? 0, cons[i] ?? 0, grow[i] ?? 0);
  }
  const yMax = Math.max(300_000, Math.ceil(hi / 60_000) * 60_000 + 60_000);
  const xPos = (d: number) => padL + (d / horizonView) * plotW;
  const yPos = (v: number) =>
    padT + (1 - Math.max(0, Math.min(yMax, v)) / yMax) * plotH;
  const lineFor = (pts: number[]) =>
    Array.from(
      { length: horizonView + 1 },
      (_, i) => `${xPos(i).toFixed(1)},${yPos(pts[i] ?? 0).toFixed(1)}`,
    ).join(" ");

  const floorY = yPos(safetyFloor);
  const months = Math.max(1, Math.floor(horizonView / 30));
  const monthTicks = Array.from({ length: months + 1 }, (_, i) => i);
  const visibleEvents = events.filter((e) => e.day <= horizonView);

  return (
    <div className="runway-chart-wrap" ref={ref}>
      <ChartStates state={state} height={H} label={label}>
        <svg className="runway-svg" viewBox={`0 0 ${W} ${H}`}>
          {/* Danger zone below floor */}
          <rect
            x={padL}
            y={floorY}
            width={plotW}
            height={padT + plotH - floorY}
            fill="var(--loss)"
            fillOpacity={0.05}
          />
          {/* Y grid */}
          {[0, 1, 2, 3, 4].map((g) => {
            const v = (yMax * g) / 4;
            return (
              <g key={g}>
                <line x1={padL} y1={yPos(v)} x2={padR} y2={yPos(v)} stroke="rgba(0,0,0,0.05)" strokeWidth={1} />
                <text
                  x={padL}
                  y={yPos(v) - 6}
                  fontFamily="var(--font-mono)"
                  fontSize="11"
                  fontWeight={500}
                  fill="var(--ink-2)"
                  letterSpacing="0.04em"
                >
                  {v === 0 ? "$0" : `$${Math.round(v / 1000)}K`}
                </text>
              </g>
            );
          })}
          {/* X month ticks */}
          {monthTicks.map((m) => {
            const d = m * 30;
            if (xPos(d) > padR + 2) return null;
            const isNow = m === 0;
            const isEnd = d >= horizonView - 1;
            return (
              <text
                key={m}
                x={xPos(d)}
                y={H - 14}
                fontFamily="var(--font-mono)"
                fontSize="11"
                fontWeight={isNow ? 600 : 500}
                fill={isNow ? "var(--ink)" : "var(--ink-2)"}
                letterSpacing="0.06em"
                textAnchor={isNow ? "start" : isEnd ? "end" : "middle"}
              >
                {isNow ? "Today" : `+${m}mo`}
              </text>
            );
          })}
          {/* Safety floor + label tab */}
          <line
            x1={padL}
            y1={floorY}
            x2={padR}
            y2={floorY}
            stroke="var(--loss)"
            strokeWidth={1.6}
            strokeDasharray="5 4"
          />
          <rect x={padR - 150} y={floorY + 6} width={144} height={16} rx={2} fill="var(--loss)" />
          <text
            x={padR - 142}
            y={floorY + 17}
            fontFamily="var(--font-mono)"
            fontSize="9"
            fontWeight={600}
            letterSpacing="0.07em"
            fill="#fff"
          >
            SAFETY FLOOR · {fmtK(safetyFloor)}
          </text>
          {/* Seasonal markers */}
          {visibleEvents.map((ev) => (
            <g key={ev.day + ev.label}>
              <line
                x1={xPos(ev.day)}
                y1={padT + 10}
                x2={xPos(ev.day)}
                y2={padT + plotH}
                stroke="var(--amber)"
                strokeWidth={0.75}
                strokeDasharray="2 3"
                opacity={0.6}
              />
              <text
                x={xPos(ev.day)}
                y={padT + 4}
                fontFamily="var(--font-mono)"
                fontSize="8.5"
                fill="var(--amber)"
                textAnchor="middle"
                letterSpacing="0.03em"
              >
                {ev.label}
              </text>
            </g>
          ))}
          {/* Today line */}
          <line
            className="today-line"
            x1={xPos(0)}
            y1={padT}
            x2={xPos(0)}
            y2={padT + plotH}
          />
          {/* Lines */}
          <polyline className="line-grow" points={lineFor(grow)} />
          <polyline className="line-cons" points={lineFor(cons)} />
          <polyline className="line-base" points={lineFor(base)} />
          {/* Start beacon */}
          <circle className="beacon" cx={xPos(0)} cy={yPos(base[0])} r={5} fill="none" stroke="var(--compass)" strokeWidth={1.4} />
          <circle className="beacon b2" cx={xPos(0)} cy={yPos(base[0])} r={5} fill="none" stroke="var(--compass)" strokeWidth={1.4} />
          <circle cx={xPos(0)} cy={yPos(base[0])} r={4.5} fill="var(--compass)" />
          <text
            x={xPos(0) + 12}
            y={yPos(base[0]) - 14}
            fontFamily="var(--font-mono)"
            fontSize="9"
            fontWeight={600}
            fill="var(--compass)"
            letterSpacing="0.06em"
          >
            TODAY · {fmtK(base[0])}
          </text>
          {/* End nodes */}
          <rect className="end-node" x={xPos(horizonView) - 5} y={yPos(grow[horizonView] ?? 0) - 5} width={10} height={10} rx={1.5} fill="var(--d-growth)" />
          <rect className="end-node" x={xPos(horizonView) - 5} y={yPos(cons[horizonView] ?? 0) - 5} width={10} height={10} rx={1.5} fill="var(--loss)" />
          <rect className="end-node" x={xPos(horizonView) - 5} y={yPos(base[horizonView] ?? 0) - 5} width={10} height={10} rx={1.5} fill="var(--d-finance)" />
        </svg>
      </ChartStates>
    </div>
  );
}
