/* ════════════════════════════════════════════════════════════════════════
   DeptHeader — canonical title block.

   Used by every Overview and every sub-page. Renders:
     - dept icon (flat color per dept)
     - title (32px/500)
     - meta (mono kicker — Live · MTD · breadcrumb · etc.)
     - actions slot (buttons on the right)

   Per OVERVIEW-UNIFICATION.md the title bar must be IDENTICAL on every
   room. Rooms only pass content; never override sizes or padding.

   NO BACK LINK. The breadcrumb lives in the meta line (e.g.
   "Operations · Inventory · 03/11"). Users navigate back via the rail
   or subnav. A separate back link adds vertical space that other pages
   don't have — causing the buttons and first section to land at
   different Y positions. See magellan_subpage_rhythm memory.
   ════════════════════════════════════════════════════════════════════════ */

import { DeptIcon, type Dept } from "./DeptIcon";

export interface DeptHeaderProps {
  dept: Dept;
  title: string;
  meta?: React.ReactNode;
  actions?: React.ReactNode;
}

export function DeptHeader({ dept, title, meta, actions }: DeptHeaderProps) {
  return (
    <div className="dept-head">
      <div className="dept-title-wrap">
        <DeptIcon dept={dept} />
        <div>
          <div className="dept-title">{title}</div>
          {meta && <div className="dept-meta">{meta}</div>}
        </div>
      </div>
      {actions && <div className="dept-actions">{actions}</div>}
    </div>
  );
}
